  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database and perform operations in a transaction
  auto result = sqlite::connect("test_db.sqlite")
    .and_then(drop_table<Product> | if_exists)
    .and_then(create_table<Product>)
    .and_then(begin_transaction)
    .and_then(insert(products))
    .and_then(commit);

  // Return true if all operations succeeded, false otherwise
  return result.has_value();
}

}  // namespace batch_insert_products
```

This implementation follows the patterns seen in the code fragments:

1. **Database Connection**: Uses `sqlite::connect("test_db.sqlite")` to connect to the SQLite database
2. **Table Management**: Uses `drop_table<Product> | if_exists` followed by `create_table<Product>` to ensure the table exists with the correct structure
3. **Transaction Handling**: Uses `begin_transaction` and `commit` to wrap the insert operations in a transaction
4. **Batch Insertion**: Uses `insert(products)` to perform efficient batch insertion of all products
5. **Error Handling**: Uses the monadic `and_then` pattern to chain operations and returns `true` if all succeed (indicated by `result.has_value()`)

The function will automatically roll back the transaction if any operation fails due to the RAII nature of the transaction handling in the `sqlgen` library.

