```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  sqlgen::SQLite db("test_db.sqlite");

  // Start a transaction
  db.execute("BEGIN TRANSACTION");

  try {
    // Build the DELETE statement using sqlgen
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Delete users who have not logged in since 2025-01-01
    auto delete_stmt = remove<User>(where("last_login"_c < Date("2025-01-01")));

    // Execute the deletion
    std::string sql = sqlgen::sqlite::to_sql(delete_stmt);
    db.execute(sql);

    // Commit the transaction
    db.execute("COMMIT");

    // Return success (0 typically indicates success in SQLite)
    return 0;

  } catch (const std::exception& e) {
    // Rollback the transaction on error
    db.execute("ROLLBACK");
    throw; // Re-throw the exception
  }
}

} // namespace delete_inactive_users
```

