#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <chrono>
#include <iomanip>
#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    // Connect to SQLite database
    sqlgen::sqlite::Database db("test_db.sqlite");

    // Create User and Post tables
    db.create_table<User>();
    db.create_table<Post>();

    // Query active users who posted between 2025-12-01 and 2025-12-31
    using namespace sqlgen;
    using namespace sqlgen::literals;

    auto results = select<ActiveUser>(
        db,
        distinct,
        columns<User::user_id, User::username>(),
        from<User>(),
        inner_join<Post>(on<Post::user_id == User::user_id>),
        where<Post::created_at >= "2025-12-01"_date && Post::created_at <= "2025-12-31"_date>
    );

    return results;
}

}  // namespace query_active_users_posts
```

Key points of the implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::Database` to connect to "test_db.sqlite"
2. **Table Creation**: Calls `create_table<User>()` and `create_table<Post>()` to ensure tables exist
3. **Query Construction**: Uses the SQLGen DSL to build the query:
   - `select<ActiveUser>` specifies the result type
   - `distinct` ensures unique users
   - `columns<User::user_id, User::username>()` selects the specific fields
   - `from<User>()` specifies the main table
   - `inner_join<Post>(on<Post::user_id == User::user_id>)` performs the join
   - `where<Post::created_at >= "2025-12-01"_date && Post::created_at <= "2025-12-31"_date>` filters by date range
4. **Date Literals**: Uses `"2025-12-01"_date` syntax for date comparisons
5. **Return Type**: Returns `std::vector<ActiveUser>` as required

The implementation follows the SQLGen library patterns shown in the code fragments, particularly the view-based query approach demonstrated in the test files.

