namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database and create tables
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
                .and_then(create_table<Course> | if_not_exists)
                .and_then(create_table<Enrollment> | if_not_exists)
                .and_then([](auto conn) {
                  // Query for course enrollment statistics
                  return select(
                    "title"_c(&Course::title),
                    count("student_count"_c, &Enrollment::enrollment_id),
                    avg("avg_grade"_c, &Enrollment::grade)
                  )
                  .from<Course>()
                  .left_join<Enrollment>()
                  .on("course_id"_c(&Course::course_id) == "course_id"_c(&Enrollment::course_id))
                  .group_by("course_id"_c(&Course::course_id), "title"_c(&Course::title))
                  .read<std::vector<CourseStatsView>>(conn);
                });

  // Convert CourseStatsView to CourseStats
  if (result) {
    auto stats_views = result.value();
    std::vector<CourseStats> course_stats;
    course_stats.reserve(stats_views.size());

    for (const auto& view : stats_views) {
      course_stats.push_back(CourseStats{
        .title = view.title,
        .student_count = view.student_count,
        .avg_grade = view.avg_grade
      });
    }

    return course_stats;
  }

  // Return empty vector if query failed
  return {};
}

}  // namespace query_course_enrollment_stats
