  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables if they don't exist
  conn.execute(create_table_if_not_exists<Customer>());
  conn.execute(create_table_if_not_exists<Product>());
  conn.execute(create_table_if_not_exists<Order>());
  conn.execute(create_table_if_not_exists<OrderItem>());

  // Build the query using sqlgen's query builder
  auto query = select(column<Product>(&Product::name).as("product_name"),
                    column<Order>(&Order::order_date).as("order_date"),
                    column<OrderItem>(&OrderItem::quantity).as("quantity"))
              .from<Customer>()
              .join<Order>(on<Customer, Order>(&Customer::customer_id, &Order::customer_id))
              .join<OrderItem>(on<Order, OrderItem>(&Order::order_id, &OrderItem::order_id))
              .join<Product>(on<OrderItem, Product>(&OrderItem::product_id, &Product::product_id))
              .where(column<Customer>(&Customer::customer_id) == customer_id)
              .order_by(column<Order>(&Order::order_date), desc);

  // Execute the query and return results
  return conn.execute(query);
}

}  // namespace query_customer_purchase_history

