#include <gtest/gtest.h>
#include "query_high_value_orders.hpp"

namespace query_high_value_orders {

TEST(sqlite, query_high_value_orders) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Order>(conn);
  drop<Customer>(conn);
  create_table<Customer>(conn);
  create_table<Order>(conn);

  insert(conn, std::vector<Customer>{{1, "Alice"}, {2, "Bob"}});
  insert(conn, std::vector<Order>{{1, 1, 2000.0, "2025-01-01 00:00:00"},
                                  {2, 1, 500.0, "2025-01-02 00:00:00"},
                                  {3, 2, 3000.0, "2025-01-03 00:00:00"}});

  auto res = query_high_value_orders();
  ASSERT_EQ(res.size(), 2u);
  EXPECT_EQ(res[0].total_amount, 3000.0);
  EXPECT_EQ(res[1].total_amount, 2000.0);
}

}  // namespace query_high_value_orders

