```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_high_value_orders {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct OrderView {
  static constexpr const char* tablename = "HighValueOrderView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string name;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

std::vector<OrderView> query_high_value_orders() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Create database connection
  sqlite::Connection conn("test_db.sqlite");

  // Build the query using sqlgen
  auto query = select(
    column<Order>(&Order::order_id).as(&OrderView::order_id),
    column<Customer>(&Customer::name).as(&OrderView::name),
    column<Order>(&Order::total_amount).as(&OrderView::total_amount),
    column<Order>(&Order::order_date).as(&OrderView::order_date)
  ).from(
    table<Order>().as("o").inner_join(table<Customer>().as("c")).on(
      column<Order>(&Order::customer_id) == column<Customer>(&Customer::customer_id)
    )
  ).where(
    column<Order>(&Order::total_amount) > 1000.0
  ).order_by(
    desc(column<Order>(&Order::total_amount))
  );

  // Execute the query and return results
  return conn.query<OrderView>(query);
}

}  // namespace query_high_value_orders
