  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create SQLite connection
    sqlgen::sqlite::Connection conn("test_db.sqlite");

    // Build the query using sqlgen
    auto query = sqlgen::read<std::vector<ProductSalesReport>> |
                 from<Product, Sale> |
                 inner_join<Sale>(on("Product.product_id"_c == "Sale.product_id"_c)) |
                 group_by("Product.category"_c) |
                 having(sum("Sale.amount"_c) > 5000) |
                 select("Product.category"_c, 
                        sum("Sale.quantity"_c).as("total_qty"), 
                        sum("Sale.amount"_c).as("total_amt"));

    // Execute the query
    auto results = conn | query;

    // Convert ProductSalesReport to CategoryReport
    std::vector<CategoryReport> reports;
    for (const auto& result : results) {
        reports.push_back({
            result.category,
            result.total_qty,
            result.total_amt
        });
    }

    return reports;
}

}  // namespace query_product_sales_report
