```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn) {
        return false;
    }

    // Use transaction for batched updates
    auto transaction = conn->begin_transaction();
    if (!transaction) {
        return false;
    }

    try {
        // Update each document with the given IDs
        for (const auto& id : ids) {
            auto update_result = transaction.and_then(
                update<Document>()
                    .set("is_deleted"_c = 1, "deleted_at"_c = sqlgen::DateTime::now())
                    .where("doc_id"_c == id)
            );

            if (!update_result) {
                transaction.rollback();
                return false;
            }
        }

        // Commit the transaction
        auto commit_result = transaction.commit();
        return commit_result.has_value();

    } catch (const std::exception& e) {
        transaction.rollback();
        return false;
    }
}

}  // namespace soft_delete_records
