```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
      .and_then([=](auto conn) {
          return conn.begin_transaction()
              .and_then([=](auto conn) {
                  // First check if sender has sufficient balance
                  return conn.read<Account>(where("account_id = ?"_sql, from_account_id))
                      .and_then([=](auto conn, auto accounts) {
                          if (accounts.empty() || accounts[0].balance < amount) {
                              // Insufficient funds, rollback and return false
                              return conn.rollback().and_then([](auto conn) {
                                  return result::ok(conn, false);
                              });
                          }

                          // Update sender's account (deduct amount)
                          return conn.update<Account>(
                              set("balance = balance - ?"_sql, amount),
                              where("account_id = ?"_sql, from_account_id)
                          ).and_then([=](auto conn, int rows_updated) {
                              if (rows_updated != 1) {
                                  // Update failed, rollback
                                  return conn.rollback().and_then([](auto conn) {
                                      return result::ok(conn, false);
                                  });
                              }

                              // Update receiver's account (add amount)
                              return conn.update<Account>(
                                  set("balance = balance + ?"_sql, amount),
                                  where("account_id = ?"_sql, to_account_id)
                              ).and_then([=](auto conn, int rows_updated) {
                                  if (rows_updated != 1) {
                                      // Update failed, rollback
                                      return conn.rollback().and_then([](auto conn) {
                                          return result::ok(conn, false);
                                      });
                                  }

                                  // Both updates successful, commit transaction
                                  return conn.commit().and_then([](auto conn) {
                                      return result::ok(conn, true);
                                  });
                              });
                          });
                      });
              });
      });

  return result.has_value() ? result.value() : false;
}

}  // namespace transaction_transfer_funds
```

