```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  try {
    // Connect to the database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");
    if (!db) {
      return false;
    }

    // First, drop the view if it exists to ensure clean creation
    auto drop_result = db->execute("DROP VIEW IF EXISTS SalesSummary");
    if (!drop_result) {
      return false;
    }

    // Create the view using create_as with the SELECT query
    auto create_result = db->and_then(
      create_as<SalesSummary>(
        select(
          "p.name"_c.as("product_name"),
          sum("s.quantity"_c).as("total_quantity"),
          sum("s.amount"_c).as("total_revenue")
        ).from<Sale>("s")
         .join<Product>("p")
         .on("s.product_id"_c == "p.product_id"_c)
         .group_by("p.name"_c)
      )
    );

    return create_result.has_value();
  } catch (const std::exception& e) {
    return false;
  }
}

}  // namespace schema_create_view_sales_summary
