bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  auto conn = conn_result.value();

  // Create table if it doesn't exist
  auto create_result = conn.and_then(create_table<Inventory> | if_not_exists);
  if (!create_result) {
    return false;
  }

  // Perform upsert (insert or replace) operations
  for (const auto& item : items) {
    auto upsert_result = conn.and_then(replace(item));
    if (!upsert_result) {
      return false;
    }
  }

  // Read back all items to verify upsert behavior
  auto read_result = conn.and_then(read<std::vector<Inventory>>);
  if (!read_result) {
    return false;
  }

  const auto& read_items = read_result.value();

  // Verify that all upserted items exist in the database with correct values
  std::unordered_map<int, Inventory> db_items_map;
  for (const auto& db_item : read_items) {
    db_items_map[db_item.item_id.value] = db_item;
  }

  for (const auto& original_item : items) {
    auto it = db_items_map.find(original_item.item_id.value);
    if (it == db_items_map.end()) {
      return false; // Item not found in database
    }

    const auto& db_item = it->second;
    if (db_item.name != original_item.name || db_item.quantity != original_item.quantity) {
      return false; // Item values don't match
    }
  }

  return true;
}

}  // namespace upsert_inventory_items

