 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  // Connect to the SQLite database
  sqlgen::sqlite::Credentials credentials{.path = "test_db.sqlite"};
  auto db = sqlgen::sqlite::Database{credentials};

  // Create the join query using sqlgen
  auto query = sqlgen::select(
      sqlgen::columns(
          sqlgen::alias<"order_id">(&Order::order_id),
          sqlgen::alias<"customer_name">(&Customer::name),
          sqlgen::alias<"amount">(&Payment::amount)
      ),
      sqlgen::from<Order>(),
      sqlgen::inner_join<Customer>(sqlgen::on(&Order::customer_id, &Customer::customer_id)),
      sqlgen::inner_join<Payment>(sqlgen::on(&Order::order_id, &Payment::order_id)),
      sqlgen::order_by(&Payment::amount, sqlgen::desc)
  );

  // Execute the query and return the results
  return db.query<Consolidated>(query);
}

}  // namespace join_orders_customers_payments
