```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <iostream>
#include <vector>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  try {
    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Enable foreign key constraints (required for SQLite)
    conn.execute("PRAGMA foreign_keys = ON");

    // Drop tables if they exist to start fresh
    conn.execute("DROP TABLE IF EXISTS Child");
    conn.execute("DROP TABLE IF EXISTS Parent");

    // Create Parent table
    conn.execute(R"(
        CREATE TABLE Parent (
            parent_id INTEGER PRIMARY KEY,
            name TEXT NOT NULL
        )
    )");

    // Create Child table with CASCADE DELETE foreign key
    conn.execute(R"(
        CREATE TABLE Child (
            child_id INTEGER PRIMARY KEY,
            parent_id INTEGER,
            note TEXT,
            FOREIGN KEY (parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE
        )
    )");

    // Insert parent record
    Parent parent{1, "Test Parent"};
    conn.insert(parent);

    // Insert child records with the same parent_id
    Child child1{1, 1, "First child"};
    Child child2{2, 1, "Second child"};
    conn.insert(child1);
    conn.insert(child2);

    // Verify initial state - should have 1 parent and 2 children
    auto parents_before = conn.select<Parent>();
    auto children_before = conn.select<Child>();

    if (parents_before.size() != 1 || children_before.size() != 2) {
        std::cout << "Initial state verification failed" << std::endl;
        return false;
    }

    // Delete the parent record
    conn.execute("DELETE FROM Parent WHERE parent_id = 1");

    // Verify final state - parent should be deleted and children should be cascade deleted
    auto parents_after = conn.select<Parent>();
    auto children_after = conn.select<Child>();

    bool parent_deleted = parents_after.empty();
    bool children_deleted = children_after.empty();

    // Clean up
    conn.execute("DROP TABLE IF EXISTS Child");
    conn.execute("DROP TABLE IF EXISTS Parent");

    // Return verification result
    if (parent_deleted && children_deleted) {
        std::cout << "Cascade delete successful: Parent and all child records were deleted" << std::endl;
        return true;
    } else {
        std::cout << "Cascade delete failed: " 
                  << "Parent deleted: " << parent_deleted 
                  << ", Children deleted: " << children_deleted << std::endl;
        return false;
    }

  } catch (const std::exception& e) {
    std::cerr << "Error in cascade_delete_demo: " << e.what() << std::endl;
    return false;
  }
}

}  // namespace cascade_delete_demo
```

