Looking at the code fragments and the requirements, I need to implement a FULL JOIN between suppliers and products. Since SQLite doesn't natively support FULL JOIN, I'll need to simulate it using a UNION of LEFT JOIN and RIGHT JOIN operations.

Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {};
  }

  // Since SQLite doesn't support FULL JOIN directly, we simulate it with UNION of LEFT and RIGHT joins
  // First part: LEFT JOIN (all suppliers with their products)
  auto left_join_query = 
    "SELECT s.name AS supplier_name, p.name AS product_name "
    "FROM Supplier s "
    "LEFT JOIN Product p ON s.supplier_id = p.supplier_id "
    "UNION ALL "
    "SELECT s.name AS supplier_name, p.name AS product_name "
    "FROM Product p "
    "LEFT JOIN Supplier s ON s.supplier_id = p.supplier_id "
    "WHERE s.supplier_id IS NULL";

  // Execute the query and return results
  auto result = conn->and_then(sqlgen::read<std::vector<SupProd>>(left_join_query));

  if (result) {
    return result.value();
  }

  return {};
}

}  // namespace full_join_suppliers_products
```

Alternative implementation using the sqlgen query builder approach:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {};
  }

  // Define the columns we want to select
  auto supplier_name_col = "s.name"_c;
  auto product_name_col = "p.name"_c;

  // Since SQLite doesn't support FULL JOIN, we simulate it with UNION
  // First part: Suppliers LEFT JOIN Products
  auto left_join_part = 
    select(supplier_name_col.as("supplier_name"), 
           product_name_col.as("product_name"))
    .from_<Supplier>("s")
    .left_join<Product>("p").on("s.supplier_id"_c == "p.supplier_id"_c);

  // Second part: Products LEFT JOIN Suppliers where supplier is missing (RIGHT JOIN simulation)
  auto right_join_part = 
    select(supplier_name_col.as("supplier_name"), 
           product_name_col.as("product_name"))
    .from_<Product>("p")
    .left_join<Supplier>("s").on("s.supplier_id"_c == "p.supplier_id"_c)
    .where("s.supplier_id"_c.is_null());

  // Combine with UNION
  auto full_join_query = left_join_part.union_(right_join_part);

  // Execute the query
  auto result = conn->and_then(full_join_query | sqlgen::read<std::vector<SupProd>>);

  if (result) {
    return result.value();
  }

  return {};
}

}  // namespace full_join_suppliers_products
```

The first implementation uses raw SQL to perform the FULL JOIN simulation, while the second uses sqlgen's query builder. Both approaches will:

1. Connect to the "test_db.sqlite" database
2. Perform a FULL JOIN simulation using UNION of LEFT JOIN operations
3. Include all suppliers and all products (rows present in either table)
4. Return the results as a vector of SupProd structs with supplier names and optional product names

The key insight is that SQLite doesn't support FULL JOIN directly, so we simulate it by combining a LEFT JOIN (all suppliers with their products) with the missing part that a RIGHT JOIN would provide (products without suppliers).

