```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to SQLite database and create tables
  auto result = sqlite::connect("test_db.sqlite")
      .and_then(create_table<Department> | if_not_exists)
      .and_then(create_table<Employee> | if_not_exists)
      .and_then(insert(depts))
      .and_then(insert(emps));

  if (!result) {
    // Return empty analysis if connection/table creation fails
    return analysis;
  }

  // Perform INNER JOIN
  auto inner_result = result
      .and_then(query<JoinResult>(
          "SELECT d.department_name, e.first_name, e.last_name, e.salary "
          "FROM Department d "
          "INNER JOIN Employee e ON d.department_id = e.department_id"))
      .and_then(read<std::vector<JoinResult>>);

  if (inner_result) {
    analysis.inner_join_results = inner_result.value();
  }

  // Perform LEFT JOIN
  auto left_result = result
      .and_then(query<JoinResult>(
          "SELECT d.department_name, e.first_name, e.last_name, e.salary "
          "FROM Employee e "
          "LEFT JOIN Department d ON e.department_id = d.department_id"))
      .and_then(read<std::vector<JoinResult>>);

  if (left_result) {
    analysis.left_join_results = left_result.value();
  }

  // Perform RIGHT JOIN (simulated with LEFT JOIN since SQLite doesn't support RIGHT JOIN)
  auto right_result = result
      .and_then(query<JoinResult>(
          "SELECT d.department_name, e.first_name, e.last_name, e.salary "
          "FROM Department d "
          "LEFT JOIN Employee e ON d.department_id = e.department_id "
          "WHERE e.employee_id IS NULL "
          "UNION ALL "
          "SELECT d.department_name, e.first_name, e.last_name, e.salary "
          "FROM Employee e "
          "INNER JOIN Department d ON e.department_id = d.department_id"))
      .and_then(read<std::vector<JoinResult>>);

  if (right_result) {
    analysis.right_join_results = right_result.value();
  }

  // Perform FULL JOIN (simulated with UNION of LEFT and RIGHT joins)
  auto full_result = result
      .and_then(query<JoinResult>(
          "SELECT d.department_name, e.first_name, e.last_name, e.salary "
          "FROM Employee e "
          "LEFT JOIN Department d ON e.department_id = d.department_id "
          "UNION ALL "
          "SELECT d.department_name, e.first_name, e.last_name, e.salary "
          "FROM Department d "
          "LEFT JOIN Employee e ON d.department_id = e.department_id "
          "WHERE e.employee_id IS NULL"))
      .and_then(read<std::vector<JoinResult>>);

  if (full_result) {
    analysis.full_join_results = full_result.value();
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Creates the Department and Employee tables** using `create_table` with `if_not_exists` flag
3. **Inserts the provided data** using `insert()` for both departments and employees
4. **Performs all four join operations**:
   - **INNER JOIN**: Gets employees with assigned departments
   - **LEFT JOIN**: Includes all employees (even without departments)
   - **RIGHT JOIN**: Simulated using LEFT JOIN since SQLite doesn't natively support RIGHT JOIN
   - **FULL JOIN**: Simulated using UNION of LEFT JOIN and the RIGHT JOIN equivalent
5. **Returns comprehensive analysis** with results from all join operations stored in the `JoinAnalysis` structure

The code handles optional values properly using `std::optional` for fields that might be NULL in outer joins, and follows the sqlgen library patterns shown in the provided code fragments.

