Looking at the code fragments and the requirements, I need to implement the `weekday_sales_analysis` function using the `sqlgen` library. The key aspects are:

1. Connect to SQLite database "test_db.sqlite"
2. Extract weekday from sale_time (using SQLite's strftime function)
3. Aggregate total quantities by weekday
4. Return the results as a vector of WeekdayStats

Here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Connect to SQLite database
  auto db = sqlite::Database::open("test_db.sqlite");

  // Create a query to extract weekday and aggregate quantities
  // SQLite's strftime('%w', sale_time) returns weekday as 0-6 (Sunday=0)
  auto query = select(
    strftime("%w", Sales::sale_time).as("weekday"),
    sum(Sales::quantity).as("total_quantity")
  ).from<Sales>().group_by(strftime("%w", Sales::sale_time));

  // Execute the query
  auto results = db.query(query);

  // Convert results to WeekdayStats vector
  std::vector<WeekdayStats> stats;
  for (const auto& row : results) {
    stats.push_back(WeekdayStats{
      .weekday = row["weekday"].as<int>(),
      .total_quantity = row["total_quantity"].as<int>()
    });
  }

  return stats;
}

}  // namespace weekday_sales_analysis
```

